import React, { useState } from 'react';

const skillsData = [
  { name: 'HTML & CSS', level: 85 },
  { name: 'JavaScript', level: 70 },
  { name: 'React', level: 60 },
  { name: 'Bootstrap', level: 75 },
  { name: 'Tailwind CSS', level: 60 },
  { name: 'Git & GitHub', level: 65 },
];

const Skills = () => {
  const [hovered, setHovered] = useState(null);
  return (
    <section
      id="Skills"
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
      style={{ background: '#0d1117' }}
    >
      <h1 className="font-bold text-4xl text-white text-center mb-10">Skills</h1>
      <div className="w-full max-w-2xl flex flex-col gap-5">
        {skillsData.map((skill, i) => (
          <div key={i}>
            <div className="flex justify-between text-white mb-2">
              <span className="font-bold text-sm">{skill.name}</span>
              <span className="text-xs text-gray-400">{skill.level}%</span>
            </div>
            <div className="w-full rounded-full h-3" style={{ background: 'rgba(255,255,255,0.15)' }}>
              <div
                className="h-3 rounded-full transition-all duration-500"
                style={{
                  width: `${skill.level}%`,
                  background: hovered === i ? '#004097' : '#335765',
                  transition: 'background 0.3s, width 0.5s',
                }}
                onMouseEnter={() => setHovered(i)}
                onMouseLeave={() => setHovered(null)}
              />
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Skills;
